// BAD: Forces layout recalculation on every iteration
for (let i = 0; i < items.length; i++) {
  items[i].style.width = container.offsetWidth + 'px';
  //                      ^ reads layout each time!
}

// GOOD: Read once, then write in a batch
const width = container.offsetWidth; // one read
for (let i = 0; i < items.length; i++) {
  items[i].style.width = width + 'px'; // only writes
}
